document.addEventListener("DOMContentLoaded",function(){gtag("event","page_view",{page_title:document.title,page_location:window.location.href,user_type:"child_4_10"});const n=document.querySelectorAll(".game-card");n.forEach(e=>{e.addEventListener("click",function(){const t=this.querySelector(".game-title").textContent.trim(),n=this.querySelector(".game-emoji").textContent,s=this.querySelector(".new-badge")!==null,o=this.querySelector(".hot-badge")!==null;gtag("event","game_click",{event_category:"game_engagement",event_label:t,game_name:t,game_emoji:n,has_new_badge:s,has_hot_badge:o,game_url:this.getAttribute("href"),value:1})})});const s=document.querySelectorAll(".donation-card, .floating-donate .donate-button");s.forEach(e=>{e.addEventListener("click",function(){const t=this.closest(".floating-donate"),n=t?"floating":"section";gtag("event","donate_click",{event_category:"donation",event_label:"Donate $11",value:11,currency:"USD",donation_amount:11,button_location:n,click_area:this.classList.contains("donation-card")?"full_section":"button_only"})})});let a=0;const o=[25,50,75,100],e=new Set;window.addEventListener("scroll",function(){const n=window.pageYOffset,s=document.body.scrollHeight-window.innerHeight,t=Math.round(n/s*100);o.forEach(n=>{t>=n&&!e.has(n)&&(e.add(n),gtag("event","scroll",{event_category:"engagement",event_label:`scroll_depth_${n}%`,value:n,scroll_percentage:t}))}),t>=95&&!e.has("bottom")&&(e.add("bottom"),gtag("event","scroll",{event_category:"engagement",event_label:"scroll_to_bottom",value:100,scroll_percentage:t}))});let i=Date.now();window.addEventListener("beforeunload",function(){const e=Math.round((Date.now()-i)/1e3);gtag("event","timing_complete",{name:"page_load",value:e,event_category:"engagement"})});const t=document.querySelector(".hero-section");if(t)for(let n=0;n<15;n++){const e=document.createElement("div");e.className="sparkle",e.style.left=Math.random()*100+"%",e.style.top=Math.random()*100+"%",e.style.animationDelay=Math.random()*2+"s",t.appendChild(e)}})